import java.io.IOException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

public class XSSFixedServlet extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String userInput = request.getParameter("input");

        // Validate user input to prevent XSS attacks
        if (userInput != null && !userInput.isEmpty()) {
            // Encode user input before outputting it
            String encodedUserInput = encodeForHTML(userInput);

            // Output the properly encoded user input
            response.getWriter().println("User input: " + encodedUserInput);
        } else {
            response.getWriter().println("Invalid user input");
        }
    }

    private String encodeForHTML(String input) {
        return org.apache.commons.text.StringEscapeUtils.escapeHtml4(input);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
